// 8 queries de intención específicas para Eight Academy
const INTENT_QUERIES = [
  // 🔴 HOT — Intención de matrícula directa
  { query: 'matricula colegio particular Quito 2026 2027', intent_level: 'HOT', category: 'admissions_intent', reason: 'Busca activamente dónde matricular' },
  { query: 'colegio bilingue sin matricula 2026 Ecuador', intent_level: 'HOT', category: 'promo_seeker', reason: 'Busca promoción SIN MATRÍCULA — exactamente lo que ofrecemos' },
  // 🟠 WARM — Intención de cambio/mejora
  { query: 'innovación educativa colegio Quito Ecuador', intent_level: 'WARM', category: 'innovation_seeker', reason: 'Valora innovación — perfil ideal Eight Academy' },
  { query: 'emprendimiento digital niños adolescentes Ecuador', intent_level: 'WARM', category: 'entrepreneurship_parent', reason: 'Quiere emprendimiento para su hijo — único en EA' },
  { query: 'STEM tecnología colegio primaria bachillerato Quito', intent_level: 'WARM', category: 'tech_education', reason: 'Busca educación tecnológica' },
  { query: 'educacion no tradicional metodologia activa Ecuador', intent_level: 'WARM', category: 'alternative_ed', reason: 'No quiere educación tradicional — perfil EA' },
  // 🟡 DISCOVERY — Relacionados con diferenciadores únicos de EA
  { query: 'aula metaverso realidad virtual educacion Ecuador 2026', intent_level: 'DISCOVERY', category: 'vr_education', reason: 'Busca metaverso/VR — exclusivo de Eight Academy' },
  { query: 'colegio zoo naturaleza animales aprendizaje Quito', intent_level: 'DISCOVERY', category: 'nature_education', reason: 'Interés en aprendizaje con naturaleza — Zoo Botánica' }
];

return INTENT_QUERIES.map(q => ({ json: q }));

// Extraer resultados + context query
const searchResp = $input.first().json;
const queryData = $('🔄 Loop 8 Queries').first().json;

const results = searchResp.web?.results || [];

if (results.length === 0) {
  return [{ json: {
    query: queryData.query,
    intent_level: queryData.intent_level,
    category: queryData.category,
    results_count: 0,
    results_summary: 'Sin resultados',
    _skip: true
  }}];
}

const resultsSummary = results.slice(0, 8).map(r => `• ${r.title} | ${r.description || ''} | ${r.url}`).join('\n');

return [{ json: {
  query: queryData.query,
  intent_level: queryData.intent_level,
  category: queryData.category,
  reason: queryData.reason,
  results_count: results.length,
  results_summary: resultsSummary,
  top_urls: results.slice(0, 5).map(r => r.url).join('|'),
  _skip: false
}}];

const aiResp = $input.first().json;
const rawText = aiResp.content?.[0]?.text || '{}';
const queryData = $('⚡ ¿Tiene Resultados?').first().json;

let ai = {};
try {
  const cleaned = rawText.replace(/```json/gi,'').replace(/```/gi,'').trim();
  ai = JSON.parse(cleaned);
} catch(e) {
  ai = { intent_strength: 5, opportunity_type: 'nuevo_prospecto', urgency: 'media' };
}

const actions = (ai.recommended_actions || []).join(' | ');
const leads = (ai.actionable_leads || []).join(' | ');
const orgs = (ai.organizations_found || []).join(' | ');

return [{ json: {
  Semana: new Date().toISOString().split('T')[0],
  Query: queryData.query,
  Nivel_Intencion: queryData.intent_level,
  Categoria: queryData.category,
  Fuerza_Intencion: ai.intent_strength || 0,
  Tipo_Oportunidad: ai.opportunity_type || '',
  Audiencia_Objetivo: ai.target_audience || '',
  Angulo_EA: ai.eight_academy_angle || '',
  Organizaciones: orgs,
  Leads_Accionables: leads,
  Oportunidad_Contenido: ai.content_opportunity || '',
  Insight_Competencia: ai.competitor_insight || '',
  Urgencia: ai.urgency || 'media',
  Acciones: actions,
  _intent_strength: ai.intent_strength || 0,
  _urgency: ai.urgency || 'media',
  _leads_raw: ai.actionable_leads || []
}}];

